#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d", &N, &Q);
        int A[16];
        for(int i=0;i<N;i++) scanf("%d", &A[i]);
        while(Q--){
            int L,R; scanf("%d %d", &L, &R);
            L--; R--;
            long long ans=0;
            for(int i=L;i<=R;i++){
                for(int j=i;j<=R;j++){
                    int len=j-i+1;
                    int tmp[16];
                    for(int k=0;k<len;k++) tmp[k]=A[i+k];
                    qsort(tmp, len, sizeof(int), cmp);
                    int good=1;
                    for(int k=0;k+1<len;k++) if(tmp[k+1]%tmp[k]!=0){good=0;break;}
                    if(good) ans++;
                }
            }
            printf("%lld\n", ans);
        }
    }
    return 0;
}

