            for(int i=L;i<=R;i++){
                for(int j=i;j<=R;j++){
                    vector<int> sub(A.begin()+i, A.begin()+j+1);
                    sort(sub.begin(), sub.end());
                    bool good=true;
                    for(size_t k=0;k+1<sub.size();k++) if(sub[k+1]%sub[k]!=0){good=false;break;}
                    if(good) ans++;
                }
            }
            cout<<ans<<"\n";
        }
    }
    return 0;
