import sys

def is_good(arr):
    arr = sorted(arr)
    for i in range(len(arr)-1):
        if arr[i+1] % arr[i] != 0:
            return False
    return True

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); Q = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        for __ in range(Q):
            L = int(next(it)) - 1
            R = int(next(it)) - 1
            ans = 0
            for i in range(L, R+1):
                for j in range(i, R+1):
                    if is_good(A[i:j+1]):
                        ans += 1
            out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

